import {
  normalizeAPIResponse,
  normalizeStatus,
} from '../utils/apiHelpers';

// ─────────────────────────────────────────────────────────────
// STATUS CONFIG
// ─────────────────────────────────────────────────────────────
const STATUS_CONFIG = {
  pending: {
    color:   'gold',
    icon:    'bi-hourglass-split',
    message: 'Your application is under review by the librarian.',
  },
  'approved by librarian': {
    color:   'blue',
    icon:    'bi-person-check',
    message: 'Approved by librarian — awaiting final admin approval.',
  },
  approved: {
    color:   'green',
    icon:    'bi-check-circle-fill',
    message: 'Your library card is active. Happy reading! 📚',
  },
  rejected: {
    color:   'red',
    icon:    'bi-x-circle-fill',
    message: 'Your application was rejected. See the reason below.',
  },
};

const getStatusConfig = (status) =>
  STATUS_CONFIG[normalizeStatus(status)] ?? {
    color:   'blue',
    icon:    'bi-info-circle',
    message: 'Status unknown — contact the library.',
  };

// ─────────────────────────────────────────────────────────────
// INITIAL FORM STATE
// ─────────────────────────────────────────────────────────────
const INITIAL_FORM = {
  course:        '',
  branch:        '',
  semester:      '',
  contactNumber: '',
  address:       '',
};

// ─────────────────────────────────────────────────────────────
// MAIN COMPONENT
// ─────────────────────────────────────────────────────────────
const RequestCardPage = () => {
  const { currentUser } = useAuth();

  const [existingCard, setExistingCard] = useState(null);
  const [formData,     setFormData]     = useState(INITIAL_FORM);
  const [loading,      setLoading]      = useState(true);
  const [submitting,   setSubmitting]   = useState(false);
  const [error,        setError]        = useState(null);
  const [successMsg,   setSuccessMsg]   = useState('');

  // ── Fetch existing card ───────────────────────────────────
  const fetchCard = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await libraryCardsAPI.getMyCard();
      setExistingCard(normalizeAPIResponse(res) ?? null);
    } catch (err) {
      // 404 = no card yet — perfectly normal
      if (err?.response?.status === 404 || err?.statusCode === 404) {
        setExistingCard(null);
      } else {
        console.error('RequestCardPage fetch error:', err);
        setError('Could not load your library card details.');
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCard();
  }, []);

  // ── Form handlers ─────────────────────────────────────────
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    setError(null);
    setSuccessMsg('');

    // Basic validation
    if (!formData.course.trim() || !formData.branch.trim()) {
      setError('Course and Branch are required.');
      setSubmitting(false);
      return;
    }

    try {
      const res  = await libraryCardsAPI.request(formData);
      const card = normalizeAPIResponse(res);
      setExistingCard(card ?? { ...formData, status: 'pending' });
      setSuccessMsg('Application submitted successfully! We will notify you once reviewed.');
      setFormData(INITIAL_FORM);
    } catch (err) {
      const message =
        err?.response?.data?.message ??
        err?.message ??
        'Submission failed. Please try again.';
      setError(message);
    } finally {
      setSubmitting(false);
    }
  };

  // ── Render ────────────────────────────────────────────────
  if (loading)
    return (
      <div className="text-center py-5">
        <div className="spinner-border text-primary"></div>
        <p className="mt-2 text-muted">Loading card status…</p>
      </div>
    );

  const cfg = existingCard ? getStatusConfig(existingCard.status) : null;

  return (
    <div className="page-wrapper">
      <div className="container" style={{ maxWidth: 700 }}>

        {/* Header */}
        <div className="mb-4">
          <h2 className="section-title">
            <i className="bi bi-credit-card me-2"></i>Library Card
          </h2>
          <p className="text-muted" style={{ fontSize: '.9rem' }}>
            {existingCard
              ? 'Track your library card application status below.'
              : 'Apply for a library card to issue and return books.'}
          </p>
        </div>

        {/* ── EXISTING CARD STATUS ── */}
        {existingCard ? (
          <div className="lib-card">
            <div className="lib-card-header">
              <h5>
                <i className={`bi ${cfg.icon} me-2`}></i>
                Application Status
              </h5>
            </div>
            <div className="p-4">

              {/* Status badge */}
              <div className="d-flex align-items-center gap-3 mb-4">
                <div
                  className={`stat-icon ${cfg.color}`}
                  style={{ width: 56, height: 56, fontSize: '1.5rem' }}
                >
                  <i className={`bi ${cfg.icon}`}></i>
                </div>
                <div>
                  <div style={{ fontWeight: 700, fontSize: '1.1rem' }}>
                    {existingCard.status ?? 'Unknown'}
                  </div>
                  <div className="text-muted" style={{ fontSize: '.88rem' }}>
                    {cfg.message}
                  </div>
                </div>
              </div>

              {/* Card details table */}
              <table className="lib-table">
                <tbody>
                  <tr>
                    <td className="text-muted" style={{ width: '40%' }}>Student</td>
                    <td>{currentUser?.name ?? 'N/A'}</td>
                  </tr>
                  <tr>
                    <td className="text-muted">Course</td>
                    <td>{existingCard.course  ?? 'N/A'}</td>
                  </tr>
                  <tr>
                    <td className="text-muted">Branch</td>
                    <td>{existingCard.branch  ?? 'N/A'}</td>
                  </tr>
                  <tr>
                    <td className="text-muted">Semester</td>
                    <td>{existingCard.semester ?? 'N/A'}</td>
                  </tr>
                  <tr>
                    <td className="text-muted">Applied On</td>
                    <td>
                      {existingCard.createdAt
                        ? new Date(existingCard.createdAt).toLocaleDateString()
                        : 'N/A'}
                    </td>
                  </tr>
                  {normalizeStatus(existingCard.status) === 'rejected' &&
                    existingCard.rejectionReason && (
                      <tr>
                        <td className="text-muted">Reason</td>
                        <td style={{ color: 'var(--danger)' }}>
                          {existingCard.rejectionReason}
                        </td>
                      </tr>
                    )}
                </tbody>
              </table>

              {/* Allow re-apply if rejected */}
              {normalizeStatus(existingCard.status) === 'rejected' && (
                <div className="mt-3">
                  <button
                    className="btn btn-lib-primary"
                    onClick={() => setExistingCard(null)}
                  >
                    <i className="bi bi-arrow-repeat me-1"></i>
                    Apply Again
                  </button>
                </div>
              )}
            </div>
          </div>
        ) : (

          /* ── APPLICATION FORM ── */
          <div className="lib-card">
            <div className="lib-card-header">
              <h5><i className="bi bi-file-earmark-text me-2"></i>New Application</h5>
            </div>
            <div className="p-4">

              {error && (
                <div className="alert alert-danger mb-3" role="alert">
                  <i className="bi bi-exclamation-triangle me-2"></i>{error}
                </div>
              )}

              {successMsg && (
                <div className="alert alert-success mb-3" role="alert">
                  <i className="bi bi-check-circle me-2"></i>{successMsg}
                </div>
              )}

              <div onSubmit={handleSubmit}>
                <div className="row g-3">

                  <div className="col-md-6">
                    <label className="form-label fw-semibold" style={{ fontSize: '.85rem' }}>
                      Course <span className="text-danger">*</span>
                    </label>
                    <input
                      type="text"
                      className="form-control"
                      name="course"
                      value={formData.course}
                      onChange={handleChange}
                      placeholder="e.g. B.Tech, MBA"
                      required
                    />
                  </div>

                  <div className="col-md-6">
                    <label className="form-label fw-semibold" style={{ fontSize: '.85rem' }}>
                      Branch <span className="text-danger">*</span>
                    </label>
                    <input
                      type="text"
                      className="form-control"
                      name="branch"
                      value={formData.branch}
                      onChange={handleChange}
                      placeholder="e.g. Computer Science"
                      required
                    />
                  </div>

                  <div className="col-md-6">
                    <label className="form-label fw-semibold" style={{ fontSize: '.85rem' }}>
                      Semester
                    </label>
                    <input
                      type="text"
                      className="form-control"
                      name="semester"
                      value={formData.semester}
                      onChange={handleChange}
                      placeholder="e.g. 3rd"
                    />
                  </div>

                  <div className="col-md-6">
                    <label className="form-label fw-semibold" style={{ fontSize: '.85rem' }}>
                      Contact Number
                    </label>
                    <input
                      type="tel"
                      className="form-control"
                      name="contactNumber"
                      value={formData.contactNumber}
                      onChange={handleChange}
                      placeholder="10-digit number"
                    />
                  </div>

                  <div className="col-12">
                    <label className="form-label fw-semibold" style={{ fontSize: '.85rem' }}>
                      Address
                    </label>
                    <textarea
                      className="form-control"
                      name="address"
                      value={formData.address}
                      onChange={handleChange}
                      placeholder="Your current address"
                      rows={3}
                    />
                  </div>

                  <div className="col-12">
                    <button
                      className="btn btn-lib-primary"
                      disabled={submitting}
                      onClick={handleSubmit}
                    >
                      {submitting ? (
                        <>
                          <span className="spinner-border spinner-border-sm me-2"></span>
                          Submitting…
                        </>
                      ) : (
                        <>
                          <i className="bi bi-send me-1"></i>
                          Submit Application
                        </>
                      )}
                    </button>
                  </div>

                </div>
              </div>
            </div>
          </div>
        )}

      </div>
    </div>
  );
};

export default RequestCardPage;
